def md_for(slug,data):
    title, verdict, bottom, kicker, metrics, cases, buy, fran, comp, fin, kill, sources=data
    return f'''# {title} — Deep Dive Investment Memo\n\n## Verdict: {verdict}\n{bottom}\n\n## 1. Category Definition & Demand Map\n- What is this business? {title} is a local operating business built around repeat service, route execution, and documented customer relationships rather than passive ownership. The underwriteable version has manager-run SOPs and enough density for a paid operator partner.\n- Who are the customers? Mix varies by category, but the target buyer base is the recurring or repeat segment rather than one-time retail customers. Dan should segment B2B/accounts separately from B2C/spot demand.\n- Demand drivers: recurring need, compliance or lifecycle triggers, aging infrastructure/consumer base, and local convenience. Growth should be proven with account retention and local pricing, not generic TAM claims.\n- Geographic relevance: Boston/NE and NY/CT/NJ are primary because density helps route economics; SFL is attractive where aging demographics, hospitality, construction, or healthcare demand fit.\n- Market size: public category-specific precision is limited; use cited public sources for demand backdrop and label local revenue/SDE cases as estimates until broker/operator data is obtained.\n\n## 2. Economics to Underwrite\n| Metric | Typical Range | Source |\n|--------|--------------|--------|\n''' + ''.join(f'| {m[0]} | {m[1]} | {m[2]} |\n' for m in metrics) + f'''\n## 3. Unit Economics Model (Three-Case)\n\n| Case | Revenue | SDE | SDE Margin | Entry Price | Multiple | Cash-on-Cash Year 1 |\n|------|---------|-----|-----------|-------------|----------|---------------------|\n''' + ''.join(f'| {c[0]} | {c[1]} | {c[2]} | {c[3]} | {c[4]} | {c[5]} | {c[6]} |\n' for c in cases) + '''\n**Key assumptions:**\n- Entry multiples: 3-4.5x SDE at Dan's scale ($200-500K SDE). NOT 8-10x.\n- SBA 7(a): 10-year term, ~11% rate (2026), 10% down.\n- Cash-on-cash = (SDE - estimated debt service) / down payment.\n- Operator partner: Dan can hire/partner with an operator — diligence should focus on whether a manager can run the day-to-day.\n\n''' + f'''## 4. Path-Specific Buybox\nWhat makes a GOOD acquisition target in this category?\n- Revenue range / SDE range / assets: {buy}\n\nWhat makes a good FRANCHISE candidate?\n- {fran}\n\n## 5. Competitive Landscape\n- {comp}\n\n## 6. Financing, Valuation & Capital Discipline\n- {fin}\n\n## 7. 90-Day Roadmap (If Dan Pursues This)\n- Phase 1 (Days 1-30): Market map target geographies, scrape broker listings, identify 20-50 local operators, request any franchise/FDD materials, and build a first-pass lender model.\n- Phase 2 (Days 31-60): Diligence 3-5 targets, verify tax returns/job-level data/customer retention, interview operator-partner candidates, and pressure-test insurance/licensing/capex.\n- Phase 3 (Days 61-90): Submit one LOI with seller note/retention mechanics or kill the category; if franchise-led, decide whether FDD economics beat independent acquisition.\n\n## 8. Kill Criteria\nWhat would make this a NO-GO?\n- {kill}\n\n## Sources\n''' + ''.join(f'- {s}\n' for s in sources)

def md_to_html(md):
    lines=md.splitlines(); out=[]; in_ul=False; in_table=False
    def close_ul():
        nonlocal in_ul
        if in_ul: out.append('</ul>'); in_ul=False
    def close_table():
        nonlocal in_table
        if in_table: out.append('</table>'); in_table=False
    for line in lines[1:]:
        if not line.strip(): continue
        if line.startswith('## '): close_ul(); close_table(); out.append(f'<h2>{html.escape(line[3:])}</h2>')
        elif line.startswith('- '): close_table();
        # handle after due Python limitation
        elif False: pass
        elif line.startswith('|'):
            close_ul(); cells=[c.strip() for c in line.strip('|').split('|')]
            if set(cells[0])<=set('-:') or cells[0]=='--------': continue
            if not in_table: out.append('<table>'); in_table=True
            tag='th' if all(x in ['Metric','Typical Range','Source','Case','Revenue','SDE','SDE Margin','Entry Price','Multiple','Cash-on-Cash Year 1'] for x in cells) else 'td'
            out.append('<tr>'+''.join(f'<{tag}>{html.escape(c)}</{tag}>' for c in cells)+'</tr>')
        elif line.startswith('**') and line.endswith('**'):
            close_ul(); close_table(); out.append(f'<p><strong>{html.escape(line.strip("*"))}</strong></p>')
        else:
            close_ul(); close_table(); out.append(f'<p>{html.escape(line)}</p>')
    close_ul(); close_table(); return '\n'.join(out)
