def body_html(md):
    lines=md.splitlines(); out=[]; in_ul=False; in_table=False
    def close_ul():
        nonlocal in_ul
        if in_ul: out.append('</ul>'); in_ul=False
    def close_table():
        nonlocal in_table
        if in_table: out.append('</table>'); in_table=False
    for line in lines[1:]:
        if not line.strip(): continue
        if line.startswith('## '): close_ul(); close_table(); out.append(f'<h2>{html.escape(line[3:])}</h2>')
        elif line.startswith('- '): close_table();
        
        
        if line.startswith('- '):
            if not in_ul: out.append('<ul>'); in_ul=True
            out.append(f'<li>{html.escape(line[2:])}</li>')
        elif line.startswith('|'):
            close_ul(); cells=[c.strip() for c in line.strip('|').split('|')]
            if all(set(c)<=set('-:') for c in cells): continue
            if not in_table: out.append('<table>'); in_table=True
            header=cells[0] in ('Metric','Case')
            tag='th' if header else 'td'
            out.append('<tr>'+''.join(f'<{tag}>{html.escape(c)}</{tag}>' for c in cells)+'</tr>')
        elif line.startswith('## '):
            pass
        elif line.startswith('**') and line.endswith('**'):
            close_ul(); close_table(); out.append(f'<p><strong>{html.escape(line.strip("*"))}</strong></p>')
        elif not line.startswith('#'):
            close_ul(); close_table(); out.append(f'<p>{html.escape(line)}</p>')
    close_ul(); close_table(); return '\n'.join(out)

